function.body:
v_ResultStr VARCHAR2(2000):='';
    v_Message VARCHAR2(2000):='';
    v_Record_ID VARCHAR2(32);
    v_orden_servicio VARCHAR2(32);
    v_User_ID VARCHAR2(32);
    v_count_desp_activos NUMBER;
    v_Result NUMBER:=1;
    TYPE RECORD IS REF CURSOR;
    Cur_Parameter RECORD;

BEGIN

DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || p_PInstance_ID);
    v_ResultStr:='PInstanceNotFound';
    AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'Y', NULL, NULL);

begin

FOR Cur_Parameter IN
          (SELECT i.Record_ID,
            i.AD_User_ID,
            p.ParameterName,
            p.P_String,
            p.P_Number,
            p.P_Date,
            i.AD_Org_ID,
            i.AD_Client_ID
          FROM AD_PInstance i
          LEFT JOIN AD_PInstance_Para p
            ON i.AD_PInstance_ID=p.AD_PInstance_ID
          WHERE i.AD_PInstance_ID=p_PInstance_ID
          ORDER BY p.SeqNo)
        LOOP
          v_orden_servicio:=Cur_Parameter.Record_ID;
          v_User_ID:=Cur_Parameter.AD_User_ID;
        END LOOP;    

	select count(*)
	into v_count_desp_activos
	from m_inout desp, indsup_ord_desp ord
	where desp.m_inout_id=ord.m_inout_id
	and ord.atindpo_postventa_id=v_orden_servicio
	and desp.docstatus='CO'
	group by desp.m_inout_id;

	if v_count_desp_activos>0 then

		v_Message:='No se puede Reactivar Orden - Tiene Despachos Asociados';
		raise exception '%',v_Message;

	else

		DROP TRIGGER atindpo_val_borra_lin_trg ON public.atindpo_postventalinea;
		DROP TRIGGER atindpo_val_cantidad_lin_trg ON public.atindpo_postventalinea;

		update atindpo_postventalinea
		set entregado='N'
		where atindpo_postventalinea_id in (select atindpo_postventalinea_id 
											from atindpo_postventalinea
											where atindpo_postventa_id=v_orden_servicio);

		update atindpo_postventa
		set crearfactura='N',docstatus='EP',docactionpv='TL',updatedby=v_User_ID
		where atindpo_postventa_id=v_orden_servicio;


		CREATE TRIGGER atindpo_val_borra_lin_trg
		BEFORE DELETE ON atindpo_postventalinea FOR EACH ROW
		EXECUTE IMMEDIATE PROCEDURE atindpo_val_borra_lin_trg();

		CREATE TRIGGER atindpo_val_cantidad_lin_trg
		BEFORE UPDATE ON atindpo_postventalinea FOR EACH ROW
		EXECUTE IMMEDIATE PROCEDURE atindpo_val_cantidad_lin_trg();

        v_Message:='@EjecucionCorrecta@';
        DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished - ' || v_Message) ;
        AD_UPDATE_PINSTANCE(p_PInstance_ID, v_User_ID, 'Y', v_Result, v_Message);
        RETURN;


	end if;



    END;
    EXCEPTION
    WHEN OTHERS THEN


        v_ResultStr:= '@ERROR=' || SQLERRM;
        DBMS_OUTPUT.PUT_LINE(v_ResultStr) ;

        AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 0, v_ResultStr);
        RETURN;
END INDSUP_ACTIVARORDEN
